    {
      "keystrokes": "python3 -c \"\nwith open('/tmp/final-desktop.ppm','rb') as f:\n    d=f.read()\ns=d.split(b'\\n',3)\nprint(s[1].decode())\np=s[3]\nfrom collections import Counter\ncc=Counter(tuple(p[i:i+3]) for i in range(0,len(p),3))\nprint(f'Unique colors: {len(cc)}')\nfor c,n in cc.most_common(5): print(f'  {c}: {n}')\n\"\n",
      "duration": 3.0
    },
    {
      "keystrokes": "convert /tmp/final-desktop.ppm /tmp/win311-final.png\n",
